        process: [['Altyapı Denetimi', 'Mevcut kurulumunuzu değerlendirin ve dağıtım hedeflerini belirleyin.'], ['Ortam Kurulumu', 'Bulut ortamlarını yapılandırın: dev, staging ve production.'], ['Konteynerleştirme', 'Taşınabilirlik ve tutarlılık için uygulamanızı Docker\'a alın.'], ['CI/CD Boru Hattı', 'Geri alma desteğiyle otomatik build, test ve dağıtım boru hatları.'], ['Güvenlik Sertleştirmesi', 'SSL, gizli yönetim, güvenlik duvarı kuralları ve IAM politikaları.'], ['İzleme ve Uyarılar', 'Çalışma süresi izleme, log toplama ve olay uyarısı.']],
